-- =====================================================================
-- Datos de prueba (DEV) — Plataforma de Donación de Órganos
-- Motor: PostgreSQL (Neon). Pensado SOLO para desarrollo/demo.
--
-- ⚠️ Este script BORRA los datos existentes de auth/core y los recrea.
--    NO ejecutar en un entorno con datos reales.
-- ⚠️ NO es una migración Flyway (no va en db/migration): se corre a mano.
--
-- Usa búsquedas por email / número de documento (no IDs fijos) para ser
-- robusto ante los IDs autogenerados (GENERATED BY DEFAULT AS IDENTITY).
-- =====================================================================

BEGIN;

-- ----- Limpieza (orden seguro por FKs) --------------------------------
DELETE FROM core.medical_reports;
DELETE FROM core.process_documents;
DELETE FROM core.process_status_history;
DELETE FROM core.donation_processes;
DELETE FROM core.donor_organs;
DELETE FROM core.recipients;
DELETE FROM core.donors;
DELETE FROM auth.medical_professional_profiles;
DELETE FROM auth.users;

-- ----- Usuarios (auth.users) ------------------------------------------
-- NOTA: password_hash es un valor DUMMY (no es un hash real). El registro
-- actual guarda texto plano; cuando se añada BCrypt + login, reemplazar.
INSERT INTO auth.users (email, password_hash, role, is_active) VALUES
    ('carla.medico@hospital.co',  'dummy-hash-carla',  'MEDICO',   TRUE),
    ('jorge.medico@hospital.co',  'dummy-hash-jorge',  'MEDICO',   TRUE),
    ('ana.donante@mail.co',       'dummy-hash-ana',    'DONANTE',  TRUE),
    ('luis.donante@mail.co',      'dummy-hash-luis',   'DONANTE',  TRUE),
    ('marta.receptor@mail.co',    'dummy-hash-marta',  'RECEPTOR', TRUE),
    ('pedro.receptor@mail.co',    'dummy-hash-pedro',  'RECEPTOR', FALSE);

-- ----- Perfiles de médico (auth.medical_professional_profiles) --------
INSERT INTO auth.medical_professional_profiles
    (user_id, full_name, document_type, document_number, rethus_registration_number,
