INSERT INTO core.donors
    (registered_by, document_type, document_number, full_name, birth_date, sex,
     blood_type, contact_phone, contact_email, address, photo_path, status, medical_notes)
VALUES
    ((SELECT id FROM auth.users WHERE email='carla.medico@hospital.co'),
     'CC', '2020202020', 'Ana María López', '1990-04-12', 'F',
     'O_POS', '3001112233', 'ana.donante@mail.co', 'Cra 10 # 20-30, Bogotá',
     'uploads/donors/ana.jpg', 'ACTIVO', 'Donante en buen estado general.'),
    ((SELECT id FROM auth.users WHERE email='carla.medico@hospital.co'),
     'CC', '2021212121', 'Luis Fernando Díaz', '1985-11-02', 'M',
     'A_POS', '3004445566', 'luis.donante@mail.co', 'Calle 45 # 12-08, Medellín',
     NULL, 'EN_EVALUACION', 'Pendiente de exámenes complementarios.');

-- ----- Órganos ofrecidos (core.donor_organs) --------------------------
INSERT INTO core.donor_organs (donor_id, organ) VALUES
    ((SELECT id FROM core.donors WHERE document_number='2020202020'), 'RINON'),
    ((SELECT id FROM core.donors WHERE document_number='2020202020'), 'HIGADO'),
    ((SELECT id FROM core.donors WHERE document_number='2021212121'), 'CORNEA');

-- ----- Receptores (core.recipients), registrados por Jorge ------------
INSERT INTO core.recipients
