-- ----- Procesos de donación (core.donation_processes), abiertos por Carla
INSERT INTO core.donation_processes (donor_id, recipient_id, current_state, opened_by) VALUES
    ((SELECT id FROM core.donors     WHERE document_number='2020202020'),
     (SELECT id FROM core.recipients WHERE document_number='3030303030'),
