        WHERE donor_id=(SELECT id FROM core.donors WHERE document_number='2020202020')),
     'REGISTRADO', 'EN_EVALUACION', 'Inicio de evaluación de compatibilidad.',
     (SELECT id FROM auth.users WHERE email='carla.medico@hospital.co')),
